mapper.select:
SELECT r.id AS "registerId", r.case_number AS "caseNumber", r.real_name AS "realName", r.gender AS "gender", r.age AS "age", r.visit_date AS "visitDate", r.visit_state AS "visitState", r.check_in_time AS "checkInTime", r.noon AS "noon", d.dept_name AS "deptName", e.realname AS "physicianName", ac.chief_complaint AS "chiefComplaint", ac.symptom_duration AS "symptomDuration", ac.history_summary AS "historySummary", ac.allergy_summary AS "allergySummary", ac.medication_summary AS "medicationSummary", ac.ai_summary AS "aiSummary", ac.suggested_exam AS "suggestedExam", CASE WHEN ac.id IS NULL THEN FALSE ELSE TRUE END AS "hasAiConsultation" FROM register r LEFT JOIN department d ON d.id = r.deptment_id LEFT JOIN employee e ON e.id = r.employee_id LEFT JOIN LATERAL ( SELECT * FROM ai_consultation_record acr WHERE acr.register_id = r.id AND acr.consultation_state = 'completed' ORDER BY acr.completion_time DESC NULLS LAST, acr.creation_time DESC LIMIT 1 ) ac ON TRUE WHERE (r.visit_state = 1 AND r.check_in_time IS NOT NULL) OR r.visit_state = 2
AND (r.case_number ILIKE CONCAT('%', #{keyword}, '%') OR r.real_name ILIKE CONCAT('%', #{keyword}, '%'))
ORDER BY r.visit_state DESC, r.check_in_time ASC NULLS LAST, r.id DESC LIMIT #{size} OFFSET #{offset}

mapper.insert:
INSERT INTO medical_record (
    register_id, readme, present, present_treat, history, allergy, physique, proposal
) VALUES (
    #{registerId}, #{readme}, #{present}, #{presentTreat}, #{history}, #{allergy}, #{physique}, #{proposal}
)

mapper.update:
UPDATE medical_record
SET diagnosis = #{diagnosis},
    cure = #{cure},
    careful = #{careful}
WHERE id = #{medicalRecordId}

mapper.select:
SELECT mt.id AS "id", mt.tech_code AS "techCode", mt.tech_name AS "techName", mt.tech_format AS "techFormat", mt.tech_price AS "techPrice", mt.tech_type AS "techType", mt.price_type AS "priceType", mt.deptment_id AS "deptmentId", d.dept_name AS "deptName" FROM medical_technology mt LEFT JOIN department d ON d.id = mt.deptment_id WHERE mt.tech_type = #{techType}
AND (mt.tech_code ILIKE CONCAT('%', #{keyword}, '%') OR mt.tech_name ILIKE CONCAT('%', #{keyword}, '%'))
ORDER BY mt.tech_name
